{"jsonrpc":"2.0","method":"sdk/message","params":{"threadId":"provider-audit-thread","message":{"type":"user","message":{"role":"user","content":[{"tool_use_id":"toolu_01Kbspkrq5vnhFKSjoiX6MFG","type":"tool_result","content":"     1→import { useRef } from "react";
     2→
     3→import type { NonDeletedExcalidrawElement } from "@excalidraw/element/types";
     4→
     5→import { useAtom, useAtomValue } from "../../editor-jotai";
     6→
     7→import { useApp, useExcalidrawSetAppState } from "../App";
     8→
     9→import { useChatAgent } from "./Chat";
    10→
    11→import {
    12→  convertMermaidToExcalidraw,
    13→  insertToEditor,
    14→  saveMermaidDataToStorage,
    15→} from "./common";
    16→import { errorAtom, chatHistoryAtom, showPreviewAtom } from "./TTDContext";
    17→
    18→import { useTTDChatStorage } from "./useTTDChatStorage";
    19→import { useMermaidRenderer } from "./hooks/useMermaidRenderer";
    20→import { useTextGeneration } from "./hooks/useTextGeneration";
    21→import { useChatManagement } from "./hooks/useChatManagement";
    22→import { TTDChatPanel } from "./Chat/TTDChatPanel";
    23→import { TTDPreviewPanel } from "./TTDPreviewPanel";
    24→
    25→import { getLastAssistantMessage } from "./utils/chat";
    26→
    27→import type { BinaryFiles } from "../../types";
    28→import type {
    29→  MermaidToExcalidrawLibProps,
    30→  TChat,
    31→  TTDPersistenceAdapter,
    32→  TTTDDialog,
    33→} from "./types";
    34→
    35→const TextToDiagramContent = ({
    36→  mermaidToExcalidrawLib,
    37→  onTextSubmit,
    38→  renderWelcomeScreen,
    39→  renderWarning,
    40→  persistenceAdapter,
    41→}: {
    42→  mermaidToExcalidrawLib: MermaidToExcalidrawLibProps;
    43→  onTextSubmit: (
    44→    props: TTTDDialog.OnTextSubmitProps,
    45→  ) => Promise<TTTDDialog.OnTextSubmitRetValue>;
    46→  renderWelcomeScreen?: TTTDDialog.renderWelcomeScreen;
    47→  renderWarning?: TTTDDialog.renderWarning;
    48→  persistenceAdapter: TTDPersistenceAdapter;
    49→}) => {
    50→  const app = useApp();
    51→  const setAppState = useExcalidrawSetAppState();
    52→
    53→  const canvasRef = useRef<HTMLDivElement | null>(null);
    54→  const [error, setError] = useAtom(errorAtom);
    55→  const [chatHistory, setChatHistory] = useAtom(chatHistoryAtom);
    56→  const showPreview = useAtomValue(showPreviewAtom);
    57→
    58→  const { savedChats } = useTTDChatStorage({ persistenceAdapter });
    59→
    60→  const lastAssistantMessage = getLastAssistantMessage(chatHistory);
    61→
    62→  const { setLastRetryAttempt } = useChatAgent();
    63→
    64→  const { data } = useMermaidRenderer({
    65→    canvasRef,
    66→    mermaidToExcalidrawLib,
    67→  });
    68→
    69→  const { onGenerate, handleAbort } = useTextGeneration({
    70→    onTextSubmit,
    71→  });
    72→
    73→  const {
    74→    isMenuOpen,
    75→    onRestoreChat,
    76→    handleDeleteChat,
    77→    handleNewChat,
    78→    handleMenuToggle,
    79→    handleMenuClose,
    80→  } = useChatManagement({ persistenceAdapter });
    81→
    82→  const onViewAsMermaid = () => {
    83→    if (typeof lastAssistantMessage?.content === "string") {
    84→      saveMermaidDataToStorage(lastAssistantMessage.content);
    85→      setAppState({
    86→        openDialog: { name: "ttd", tab: "mermaid" },
    87→      });
    88→    }
    89→  };
    90→
    91→  const handleMermaidTabClick = (message: TChat.ChatMessage) => {
    92→    const mermaidContent = message.content || "";
    93→    if (mermaidContent) {
    94→      saveMermaidDataToStorage(mermaidContent);
    95→      setAppState({
    96→        openDialog: { name: "ttd", tab: "mermaid" },
    97→      });
    98→    }
    99→  };
   100→
   101→  const handleInsertMessage = async (message: TChat.ChatMessage) => {
   102→    const mermaidContent = message.content || "";
   103→    if (!mermaidContent.trim() || !mermaidToExcalidrawLib.loaded) {
   104→      return;
   105→    }
   106→
   107→    const tempDataRef = {
   108→      current: {
   109→        elements: [] as readonly NonDeletedExcalidrawElement[],
   110→        files: null as BinaryFiles | null,
   111→      },
   112→    };
   113→
   114→    const result = await convertMermaidToExcalidraw({
   115→      canvasRef,
   116→      data: tempDataRef,
   117→      mermaidToExcalidrawLib,
   118→      setError,
   119→      mermaidDefinition: mermaidContent,
   120→      theme: app.state.theme,
   121→    });
   122→
   123→    if (result.success) {
   124→      insertToEditor({
   125→        app,
   126→        data: tempDataRef,
   127→        text: mermaidContent,
   128→        shouldSaveMermaidDataToStorage: true,
   129→      });
   130→    }
   131→  };
   132→
   133→  const handleAiRepairClick = async (message: TChat.ChatMessage) => {
   134→    const mermaidContent = message.content || "";
   135→    const errorMessage = message.error || "";
   136→
   137→    if (!mermaidContent) {
   138→      return;
   139→    }
   140→
   141→    const repairPrompt = `Fix the error in this Mermaid diagram. The diagram is:\n\n\`\`\`mermaid\n${mermaidContent}\n\`\`\`\n\nThe exception/error is: ${errorMessage}\n\nPlease fix the Mermaid syntax and regenerate a valid diagram.`;
   142→
   143→    await onGenerate({ prompt: repairPrompt, isRepairFlow: true });
   144→  };
   145→
   146→  const handleRetry = async (message: TChat.ChatMessage) => {
   147→    const messageIndex = chatHistory.messages.findIndex(
   148→      (msg) => msg.id === message.id,
   149→    );
   150→
   151→    if (messageIndex > 0) {
   152→      const previousMessage = chatHistory.messages[messageIndex - 1];
   153→      if (
   154→        previousMessage.type === "user" &&
   155→        typeof previousMessage.content === "string"
   156→      ) {
   157→        setLastRetryAttempt();
   158→        await onGenerate({
   159→          prompt: previousMessage.content,
   160→          isRepairFlow: true,
   161→        });
   162→      }
   163→    }
   164→  };
   165→
   166→  const handleInsertToEditor = () => {
   167→    insertToEditor({ app, data });
   168→  };
   169→
   170→  const handleDeleteMessage = (messageId: string) => {
   171→    const assistantMessageIndex = chatHistory.messages.findIndex(
   172→      (msg) => msg.id === messageId && msg.type === "assistant",
   173→    );
   174→
   175→    const remainingMessages = chatHistory.messages.slice(
   176→      0,
   177→      assistantMessageIndex - 1,
   178→    );
   179→
   180→    setChatHistory({
   181→      ...chatHistory,
   182→      messages: remainingMessages,
   183→    });
   184→  };
   185→
   186→  const handlePromptChange = (newPrompt: string) => {
   187→    setChatHistory((prev) => ({
   188→      ...prev,
   189→      currentPrompt: newPrompt,
   190→    }));
   191→  };
   192→
   193→  return (
   194→    <div
   195→      className={`ttd-dialog-layout ${
   196→        showPreview
   197→          ? "ttd-dialog-layout--split"
   198→          : "ttd-dialog-layout--chat-only"
   199→      }`}
   200→    >
   201→      <TTDChatPanel
   202→        chatId={chatHistory.id}
   203→        messages={chatHistory.messages}
   204→        currentPrompt={chatHistory.currentPrompt}
   205→        onPromptChange={handlePromptChange}
   206→        onGenerate={onGenerate}
   207→        isGenerating={lastAssistantMessage?.isGenerating ?? false}
   208→        generatedResponse={lastAssistantMessage?.content}
   209→        isMenuOpen={isMenuOpen}
   210→        onMenuToggle={handleMenuToggle}
   211→        onMenuClose={handleMenuClose}
   212→        onNewChat={handleNewChat}
   213→        onRestoreChat={onRestoreChat}
   214→        onDeleteChat={handleDeleteChat}
   215→        savedChats={savedChats}
   216→        activeSessionId={chatHistory.id}
   217→        onAbort={handleAbort}
   218→        onMermaidTabClick={handleMermaidTabClick}
   219→        onAiRepairClick={handleAiRepairClick}
   220→        onDeleteMessage={handleDeleteMessage}
   221→        onInsertMessage={handleInsertMessage}
   222→        onRetry={handleRetry}
   223→        onViewAsMermaid={onViewAsMermaid}
   224→        renderWarning={renderWarning}
   225→        renderWelcomeScreen={renderWelcomeScreen}
   226→      />
   227→      {showPreview && (
   228→        <TTDPreviewPanel
   229→          canvasRef={canvasRef}
   230→          hideErrorDetails={lastAssistantMessage?.errorType === "parse"}
   231→          error={error}
   232→          loaded={mermaidToExcalidrawLib.loaded}
   233→          onInsert={handleInsertToEditor}
   234→        />
   235→      )}
   236→    </div>
   237→  );
   238→};
   239→
   240→export const TextToDiagram = ({
   241→  mermaidToExcalidrawLib,
   242→  onTextSubmit,
   243→  renderWelcomeScreen,
   244→  renderWarning,
   245→  persistenceAdapter,
   246→}: {
   247→  mermaidToExcalidrawLib: MermaidToExcalidrawLibProps;
   248→  onTextSubmit(
   249→    props: TTTDDialog.OnTextSubmitProps,
   250→  ): Promise<TTTDDialog.OnTextSubmitRetValue>;
   251→  renderWelcomeScreen?: TTTDDialog.renderWelcomeScreen;
   252→  renderWarning?: TTTDDialog.renderWarning;
   253→  persistenceAdapter: TTDPersistenceAdapter;
   254→}) => {
   255→  return (
   256→    <TextToDiagramContent
   257→      mermaidToExcalidrawLib={mermaidToExcalidrawLib}
   258→      onTextSubmit={onTextSubmit}
   259→      renderWelcomeScreen={renderWelcomeScreen}
   260→      renderWarning={renderWarning}
   261→      persistenceAdapter={persistenceAdapter}
   262→    />
   263→  );
   264→};
   265→
   266→export default TextToDiagram;
   267→"}]},"parent_tool_use_id":"toolu_01VfPJk7koWxDNeYD1fPLvsg","session_id":"7ff77c20-575a-4dfe-af05-77c02c0a1025","uuid":"45847a18-5dd2-4ad3-a6ff-a08e450ce909"}}}

