  1→import { useRef } from "react";
  2→import { parseMermaidToExcalidraw } from "@excalidraw/mermaid-to-excalidraw";
  3→import { isFiniteNumber } from "@excalidraw/math";
  4→
  5→import { useAtom } from "../../../editor-jotai";
  6→
  7→import { trackEvent } from "../../../analytics";
  8→import { t } from "../../../i18n";
  9→
 10→import { errorAtom, rateLimitsAtom, chatHistoryAtom } from "../TTDContext";
 11→import { useChatAgent } from "../Chat";
 12→
 13→import {
 14→  addMessages,
 15→  getLastAssistantMessage,
 16→  getMessagesForLLM,
 17→  removeLastAssistantMessage,
 18→  updateAssistantContent,
 19→} from "../utils/chat";
 20→
 21→import type { LLMMessage, TTTDDialog } from "../types";
 22→
 23→const MIN_PROMPT_LENGTH = 3;
 24→const MAX_PROMPT_LENGTH = 10000;
 25→
 26→export const useTextGeneration = ({
 27→  onTextSubmit,
 28→}: {
 29→  onTextSubmit: (
 30→    props: TTTDDialog.OnTextSubmitProps,
 31→  ) => Promise<TTTDDialog.OnTextSubmitRetValue>;
 32→}) => {
 33→  const [, setError] = useAtom(errorAtom);
 34→  const [rateLimits, setRateLimits] = useAtom(rateLimitsAtom);
 35→  const [chatHistory, setChatHistory] = useAtom(chatHistoryAtom);
 36→
 37→  const { addUserMessage, addAssistantMessage, setAssistantError } =
 38→    useChatAgent();
 39→
 40→  const streamingAbortControllerRef = useRef<AbortController | null>(null);
 41→
 42→  const validatePrompt = (prompt: string): boolean => {
 43→    if (
 44→      prompt.length > MAX_PROMPT_LENGTH ||
 45→      prompt.length < MIN_PROMPT_LENGTH ||
 46→      rateLimits?.rateLimitRemaining === 0
 47→    ) {
 48→      if (prompt.length < MIN_PROMPT_LENGTH) {
 49→        setError(
 50→          new Error(
 51→            t("chat.errors.promptTooShort", { min: MIN_PROMPT_LENGTH }),
 52→          ),
 53→        );
 54→      }
 55→      if (prompt.length > MAX_PROMPT_LENGTH) {
 56→        setError(
 57→          new Error(t("chat.errors.promptTooLong", { max: MAX_PROMPT_LENGTH })),
 58→        );
 59→      }
 60→
 61→      return false;
 62→    }
 63→    return true;
 64→  };
 65→
 66→  const onGenerate: TTTDDialog.OnGenerate = async ({
 67→    prompt,
 68→    isRepairFlow = false,
 69→  }) => {
 70→    if (!validatePrompt(prompt)) {
 71→      return;
 72→    }
 73→
 74→    if (streamingAbortControllerRef.current) {
 75→      streamingAbortControllerRef.current.abort();
 76→    }
 77→
 78→    setError(null);
 79→
 80→    const abortController = new AbortController();
 81→    streamingAbortControllerRef.current = abortController;
 82→
 83→    if (!isRepairFlow) {
 84→      addUserMessage(prompt);
 85→      addAssistantMessage();
 86→    } else {
 87→      setChatHistory((prev) =>
 88→        updateAssistantContent(prev, {
 89→          isGenerating: true,
 90→          content: "",
 91→          error: undefined,
 92→          errorType: undefined,
 93→          errorDetails: undefined,
 94→        }),
 95→      );
 96→    }
 97→
 98→    try {
 99→      trackEvent("ai", "generate", "ttd");
100→
101→      const previousMessages = getMessagesForLLM(chatHistory);
102→
103→      const messages: LLMMessage[] = [
104→        ...previousMessages.slice(-3),
105→        { role: "user", content: prompt },
106→      ];
107→
108→      const { generatedResponse, error, rateLimit, rateLimitRemaining } =
109→        await onTextSubmit({
110→          messages,
111→          onStreamCreated: () => {
112→            if (isRepairFlow) {
113→              setChatHistory((prev) =>
114→                updateAssistantContent(prev, {
115→                  content: "",
116→                  error: "",
117→                  isGenerating: true,
118→                }),
119→              );
120→            }
121→          },
122→          onChunk: (chunk: string) => {
123→            setChatHistory((prev) => {
124→              const lastAssistantMessage = getLastAssistantMessage(prev);
125→              return updateAssistantContent(prev, {
126→                content: lastAssistantMessage.content + chunk,
127→              });
128→            });
129→          },
130→          signal: abortController.signal,
131→        });
132→
133→      setChatHistory((prev) =>
134→        updateAssistantContent(prev, {
135→          isGenerating: false,
136→        }),
137→      );
138→
139→      if (isFiniteNumber(rateLimit) && isFiniteNumber(rateLimitRemaining)) {
140→        setRateLimits({ rateLimit, rateLimitRemaining });
141→      }
142→
143→      if (error?.status === 429 || rateLimitRemaining === 0) {
144→        setChatHistory((chatHistory) => {
145→          if (error?.status === 429) {
146→            chatHistory = removeLastAssistantMessage(chatHistory);
147→          }
148→
149→          chatHistory = {
150→            ...chatHistory,
151→            messages: chatHistory.messages.filter(
152→              (msg) =>
153→                msg.type !== "warning" ||
154→                msg.warningType === "rateLimitExceeded" ||
155→                msg.warningType === "messageLimitExceeded",
156→            ),
157→          };
158→          const messages = addMessages(chatHistory, [
159→            {
160→              type: "warning",
161→              warningType:
162→                rateLimitRemaining === 0
163→                  ? "messageLimitExceeded"
164→                  : "rateLimitExceeded",
165→            },
166→          ]);
167→          return messages;
168→        });
169→      }
170→
171→      if (error) {
172→        const isAborted =
173→          error.name === "AbortError" ||
174→          error.message === "Aborted" ||
175→          abortController.signal.aborted;
176→
177→        // do nothing if the request was aborted by the user
178→        if (isAborted) {
179→          return;
180→        }
181→
182→        const _error = new Error(
183→          error.message || t("chat.errors.requestFailed"),
184→        );
185→        if (error.status !== 429) {
186→          setAssistantError(_error.message, "network");
187→        }
188→        setError(_error);
189→
190→        return;
191→      }
192→
193→      try {
194→        await parseMermaidToExcalidraw(generatedResponse ?? "");
195→        trackEvent("ai", "mermaid parse success", "ttd");
196→      } catch (error: any) {
197→        trackEvent("ai", "mermaid parse failed", "ttd");
198→        const _error = new Error(
199→          error.message || t("chat.errors.mermaidParseError"),
200→        );
201→        setAssistantError(_error.message, "parse");
202→        setError(_error);
203→      }
204→    } catch (error: any) {
205→      const _error = new Error(
206→        error.message || t("chat.errors.generationFailed"),
207→      );
208→      setAssistantError(_error.message, "other");
209→      setError(_error);
210→    } finally {
211→      streamingAbortControllerRef.current = null;
212→    }
213→  };
214→
215→  const handleAbort = () => {
216→    if (streamingAbortControllerRef.current) {
217→      streamingAbortControllerRef.current.abort();
218→    }
219→  };
220→
221→  return {
222→    onGenerate,
223→    handleAbort,
224→  };
225→};
226→

