{"jsonrpc":"2.0","method":"sdk/message","params":{"threadId":"provider-audit-thread","message":{"type":"user","message":{"role":"user","content":[{"tool_use_id":"toolu_01XoNd42qKPMVknz9erjPoxv","type":"tool_result","content":"     1→import { useRef } from "react";
