  1→import { useCallback, useState } from "react";
  2→
  3→import { useAtom, useSetAtom } from "../../../editor-jotai";
  4→
  5→import { errorAtom, chatHistoryAtom } from "../TTDContext";
  6→
  7→import { useTTDChatStorage } from "../useTTDChatStorage";
  8→
  9→import { getLastAssistantMessage } from "../utils/chat";
 10→
 11→import type { SavedChat, TTDPersistenceAdapter } from "../types";
 12→
 13→interface UseChatManagementProps {
 14→  persistenceAdapter: TTDPersistenceAdapter;
 15→}
 16→
 17→export const useChatManagement = ({
 18→  persistenceAdapter,
 19→}: UseChatManagementProps) => {
 20→  const setError = useSetAtom(errorAtom);
 21→  const [chatHistory, setChatHistory] = useAtom(chatHistoryAtom);
 22→  const [isMenuOpen, setIsMenuOpen] = useState(false);
 23→
 24→  const { restoreChat, deleteChat, createNewChatId } = useTTDChatStorage({
 25→    persistenceAdapter,
 26→  });
 27→
 28→  const applyChatToState = useCallback(
 29→    (chat: SavedChat) => {
 30→      const restoredMessages = chat.messages.map((msg) => ({
 31→        ...msg,
 32→        timestamp:
 33→          msg.timestamp instanceof Date
 34→            ? msg.timestamp
 35→            : new Date(msg.timestamp),
 36→      }));
 37→
 38→      const history = {
 39→        id: chat.id,
 40→        messages: restoredMessages,
 41→        currentPrompt: "",
 42→      };
 43→
 44→      const lastAssistantMsg = getLastAssistantMessage(history);
 45→
 46→      setError(
 47→        lastAssistantMsg?.error ? new Error(lastAssistantMsg?.error) : null,
 48→      );
 49→      setChatHistory(history);
 50→    },
 51→    [setError, setChatHistory],
 52→  );
 53→
 54→  const resetChatState = useCallback(async () => {
 55→    const newSessionId = await createNewChatId();
 56→    setChatHistory({
 57→      id: newSessionId,
 58→      messages: [],
 59→      currentPrompt: "",
 60→    });
 61→    setError(null);
 62→  }, [createNewChatId, setChatHistory, setError]);
 63→
 64→  const onRestoreChat = useCallback(
 65→    (chat: SavedChat) => {
 66→      const restoredChat = restoreChat(chat);
 67→      applyChatToState(restoredChat);
 68→
 69→      setIsMenuOpen(false);
 70→    },
 71→    [restoreChat, applyChatToState],
 72→  );
 73→
 74→  const handleDeleteChat = useCallback(
 75→    async (chatId: string, event: React.MouseEvent) => {
 76→      event.stopPropagation();
 77→
 78→      const isDeletingActiveChat = chatId === chatHistory.id;
 79→      const updatedChats = await deleteChat(chatId);
 80→
 81→      if (isDeletingActiveChat) {
 82→        if (updatedChats.length > 0) {
 83→          const nextChat = updatedChats[0];
 84→          applyChatToState(nextChat);
 85→        } else {
 86→          await resetChatState();
 87→        }
 88→      }
 89→    },
 90→    [chatHistory.id, deleteChat, applyChatToState, resetChatState],
 91→  );
 92→
 93→  const handleNewChat = useCallback(async () => {
 94→    await resetChatState();
 95→    setIsMenuOpen(false);
 96→  }, [resetChatState]);
 97→
 98→  const handleMenuToggle = useCallback(() => {
 99→    setIsMenuOpen((prev) => !prev);
100→  }, []);
101→
102→  const handleMenuClose = useCallback(() => {
103→    setIsMenuOpen(false);
104→  }, []);
105→
106→  return {
107→    isMenuOpen,
108→    onRestoreChat,
109→    handleDeleteChat,
110→    handleNewChat,
111→    handleMenuToggle,
112→    handleMenuClose,
113→  };
114→};
115→

