    32→}: TTDDialogOutputProps) => {
    33→  const errorMessage = error
    34→    ? hideErrorDetails
    35→      ? t("chat.errors.mermaidParseError")
    36→      : formatMermaidParseErrorMessage(error.message)
    37→    : null;
    38→  const syntaxGuidance =
    39→    error && !hideErrorDetails
    40→      ? getMermaidSyntaxErrorGuidance(error.message, sourceText)
