  6→import { alertTriangleIcon } from "../icons";
  7→
  8→import {
  9→  formatMermaidParseErrorMessage,
 10→  getMermaidSyntaxErrorGuidance,
 11→  isMermaidCaretLine,
 12→} from "./utils/mermaidError";
 13→
 14→interface TTDDialogOutputProps {
 15→  error: Error | null;
 16→  canvasRef: React.RefObject<HTMLDivElement | null>;
 17→  loaded: boolean;
 18→  hideErrorDetails?: boolean;
 19→  sourceText?: string;
 20→  autoFixAvailable?: boolean;
 21→  onApplyAutoFix?: () => void;
 22→}
 23→
 24→export const TTDDialogOutput = ({
 25→  error,
 26→  canvasRef,
 27→  loaded,
 28→  hideErrorDetails,
 29→  sourceText,
 30→  autoFixAvailable,
 31→  onApplyAutoFix,
 32→}: TTDDialogOutputProps) => {
 33→  const errorMessage = error
 34→    ? hideErrorDetails
 35→      ? t("chat.errors.mermaidParseError")
 36→      : formatMermaidParseErrorMessage(error.message)
 37→    : null;
 38→  const syntaxGuidance =
 39→    error && !hideErrorDetails
 40→      ? getMermaidSyntaxErrorGuidance(error.message, sourceText)
 41→      : null;
 42→  const showAutoFixButton =
 43→    !!autoFixAvailable && !!onApplyAutoFix && !hideErrorDetails;
 44→
 45→  const errorMessageLines = errorMessage?.split(/\r?\n/) ?? [];
 46→
 47→  return (
 48→    <div
 49→      className={`ttd-dialog-output-wrapper ${
 50→        error ? "ttd-dialog-output-wrapper--error" : ""
 51→      }`}
 52→    >
 53→      {error && (
 54→        <div
 55→          key="error"
 56→          data-testid="ttd-dialog-output-error"
 57→          className="ttd-dialog-output-error"
 58→        >
 59→          <div className="ttd-dialog-output-error-content">
 60→            <div className="ttd-dialog-output-error-icon">
 61→              {alertTriangleIcon}
 62→            </div>
 63→            {syntaxGuidance && (
 64→              <div className="ttd-dialog-output-error-summary">
 65→                <div className="ttd-dialog-output-error-summary__headline">
 66→                  {syntaxGuidance.summary}
 67→                </div>
 68→                <div className="ttd-dialog-output-error-summary__label">
 69→                  Likely causes:
 70→                </div>
 71→                <ul className="ttd-dialog-output-error-summary__causes">
 72→                  {syntaxGuidance.likelyCauses.map((cause) => (
 73→                    <li key={cause}>{cause}</li>
 74→                  ))}
 75→                </ul>
 76→              </div>
 77→            )}
 78→            <div className="ttd-dialog-output-error-message">
 79→              {errorMessageLines.map((line, index) => (
 80→                <span
 81→                  key={`error-line-${index}`}
 82→                  className={
 83→                    isMermaidCaretLine(line)
 84→                      ? "ttd-dialog-output-error-message__caret"
 85→                      : undefined
 86→                  }
 87→                >
 88→                  {line}
 89→                  {index < errorMessageLines.length - 1 ? "\n" : ""}
 90→                </span>
 91→              ))}
 92→            </div>
 93→            {!hideErrorDetails && (
 94→              <div className="ttd-dialog-output-error-autofix-slot">
 95→                {showAutoFixButton ? (
 96→                  <Button
 97→                    className="ttd-dialog-panel-button ttd-dialog-output-error-autofix"
 98→                    onSelect={onApplyAutoFix}
 99→                  >
100→                    {t("mermaid.autoFixAvailable")}
101→                  </Button>
102→                ) : null}
103→              </div>
104→            )}
105→          </div>
106→        </div>
107→      )}
108→      {loaded ? (
109→        <div
110→          key="canvas"
111→          className={clsx("ttd-dialog-output-canvas-container", {
112→            invisible: !!error,
113→          })}
114→        >
115→          <div ref={canvasRef} className="ttd-dialog-output-canvas-content" />
116→        </div>
117→      ) : (
118→        <Spinner size="2rem" />
119→      )}
120→    </div>
121→  );
122→};
