 1→import { Tabs as RadixTabs } from "radix-ui";
 2→import { useRef } from "react";
 3→
 4→import { isMemberOf } from "@excalidraw/common";
 5→
 6→import { useExcalidrawSetAppState } from "../App";
 7→
 8→import type { ReactNode } from "react";
 9→
10→const TTDDialogTabs = (
11→  props: {
12→    children: ReactNode;
13→  } & { dialog: "ttd"; tab: "text-to-diagram" | "mermaid" },
14→) => {
15→  const setAppState = useExcalidrawSetAppState();
16→
17→  const rootRef = useRef<HTMLDivElement>(null);
18→  const minHeightRef = useRef<number>(0);
19→
20→  return (
21→    <RadixTabs.Root
22→      ref={rootRef}
23→      className="ttd-dialog-tabs-root"
24→      value={props.tab}
25→      onValueChange={(
26→        // at least in test enviros, `tab` can be `undefined`
27→        tab: string | undefined,
28→      ) => {
29→        if (!tab) {
30→          return;
31→        }
32→        const modalContentNode =
33→          rootRef.current?.closest<HTMLElement>(".Modal__content");
34→        if (modalContentNode) {
35→          const currHeight = modalContentNode.offsetHeight || 0;
36→          if (currHeight > minHeightRef.current) {
37→            minHeightRef.current = currHeight;
38→            modalContentNode.style.minHeight = `min(${minHeightRef.current}px, 100%)`;
39→          }
40→        }
41→        if (
42→          props.dialog === "ttd" &&
43→          isMemberOf(["text-to-diagram", "mermaid"], tab)
44→        ) {
45→          setAppState({
46→            openDialog: { name: props.dialog, tab },
47→          });
48→        }
49→      }}
50→    >
51→      {props.children}
52→    </RadixTabs.Root>
53→  );
54→};
55→
56→TTDDialogTabs.displayName = "TTDDialogTabs";
57→
58→export default TTDDialogTabs;
59→

