{"jsonrpc":"2.0","method":"sdk/message","params":{"threadId":"provider-audit-thread","message":{"type":"user","message":{"role":"user","content":[{"tool_use_id":"toolu_019mPjCZkjALtPm3hxTNFXN4","type":"tool_result","content":"     1→import {
     2→  DEFAULT_EXPORT_PADDING,
