  1→import {
  2→  DEFAULT_EXPORT_PADDING,
  3→  EDITOR_LS_KEYS,
  4→  THEME,
  5→} from "@excalidraw/common";
  6→
  7→import { convertToExcalidrawElements } from "@excalidraw/element";
  8→
  9→import { exportToCanvas } from "@excalidraw/utils";
 10→
 11→import type {
 12→  NonDeletedExcalidrawElement,
 13→  Theme,
 14→} from "@excalidraw/element/types";
 15→
 16→import { EditorLocalStorage } from "../../data/EditorLocalStorage";
 17→
 18→import type { MermaidToExcalidrawLibProps } from "./types";
 19→
 20→import type { AppClassProperties, BinaryFiles } from "../../types";
 21→
 22→export const resetPreview = ({
 23→  canvasRef,
 24→  setError,
 25→}: {
 26→  canvasRef: React.RefObject<HTMLDivElement | null>;
 27→  setError: (error: Error | null) => void;
 28→}) => {
 29→  const canvasNode = canvasRef.current;
 30→
 31→  if (!canvasNode) {
 32→    return;
 33→  }
 34→  const parent = canvasNode.parentElement;
 35→  if (!parent) {
 36→    return;
 37→  }
 38→  parent.style.background = "";
 39→  setError(null);
 40→  canvasNode.replaceChildren();
 41→};
 42→
 43→export const convertMermaidToExcalidraw = async ({
 44→  canvasRef,
 45→  mermaidToExcalidrawLib,
 46→  mermaidDefinition,
 47→  setError,
 48→  data,
 49→  theme,
 50→}: {
 51→  canvasRef: React.RefObject<HTMLDivElement | null>;
 52→  mermaidToExcalidrawLib: MermaidToExcalidrawLibProps;
 53→  mermaidDefinition: string;
 54→  setError: (error: Error | null) => void;
 55→  data: React.MutableRefObject<{
 56→    elements: readonly NonDeletedExcalidrawElement[];
 57→    files: BinaryFiles | null;
 58→  }>;
 59→  theme: Theme;
 60→}): Promise<{ success: true } | { success: false; error?: Error }> => {
 61→  const canvasNode = canvasRef.current;
 62→  const parent = canvasNode?.parentElement;
 63→
 64→  if (!canvasNode || !parent) {
 65→    return { success: false };
 66→  }
 67→
 68→  if (!mermaidDefinition) {
 69→    resetPreview({ canvasRef, setError });
 70→    return { success: false };
 71→  }
 72→
 73→  let ret;
 74→  try {
 75→    const api = await mermaidToExcalidrawLib.api;
 76→
 77→    try {
 78→      ret = await api.parseMermaidToExcalidraw(mermaidDefinition);
 79→    } catch (err: unknown) {
 80→      const originalParseError = err as Error;
 81→
 82→      if (!mermaidDefinition.includes('"')) {
 83→        return { success: false, error: originalParseError };
 84→      }
 85→
 86→      try {
 87→        ret = await api.parseMermaidToExcalidraw(
 88→          mermaidDefinition.replace(/"/g, "'"),
 89→        );
 90→      } catch {
 91→        // Keep the original error so line/column references stay aligned with
 92→        // the user's unmodified input.
 93→        return { success: false, error: originalParseError };
 94→      }
 95→    }
 96→
 97→    const { elements, files = {} } = ret;
 98→    setError(null);
 99→
100→    data.current = {
101→      elements: convertToExcalidrawElements(elements, {
102→        regenerateIds: true,
103→      }),
104→      files,
105→    };
106→
107→    const canvas = await exportToCanvas({
108→      elements: data.current.elements,
109→      files: data.current.files,
110→      exportPadding: DEFAULT_EXPORT_PADDING,
111→      maxWidthOrHeight:
112→        Math.max(parent.offsetWidth, parent.offsetHeight) *
113→        window.devicePixelRatio,
114→      appState: {
115→        exportWithDarkMode: theme === THEME.DARK,
116→      },
117→    });
118→
119→    parent.style.background = "var(--default-bg-color)";
120→    canvasNode.replaceChildren(canvas);
121→    return { success: true };
122→  } catch (err: any) {
123→    parent.style.background = "var(--default-bg-color)";
124→    if (mermaidDefinition) {
125→      setError(err);
126→    }
127→
128→    // Return error so caller can display meaningful error message
129→    return { success: false, error: err };
130→  }
131→};
132→export const saveMermaidDataToStorage = (mermaidDefinition: string) => {
133→  EditorLocalStorage.set(
134→    EDITOR_LS_KEYS.MERMAID_TO_EXCALIDRAW,
135→    mermaidDefinition,
136→  );
137→};
138→
139→export const insertToEditor = ({
140→  app,
141→  data,
142→  text,
143→  shouldSaveMermaidDataToStorage,
144→}: {
145→  app: AppClassProperties;
146→  data: React.MutableRefObject<{
147→    elements: readonly NonDeletedExcalidrawElement[];
148→    files: BinaryFiles | null;
149→  }>;
150→  text?: string;
151→  shouldSaveMermaidDataToStorage?: boolean;
152→}) => {
153→  const { elements: newElements, files } = data.current;
154→
155→  if (!newElements.length) {
156→    return;
157→  }
158→
159→  app.addElementsFromPasteOrLibrary({
160→    elements: newElements,
161→    files,
162→    position: "center",
163→    fitToContent: true,
164→  });
165→  app.setOpenDialog(null);
166→
167→  if (shouldSaveMermaidDataToStorage && text) {
168→    saveMermaidDataToStorage(text);
169→  }
170→};
171→

