3878→  addElementsFromPasteOrLibrary = (opts: {
3879→    elements: readonly ExcalidrawElement[];
3880→    files: BinaryFiles | null;
3881→    position: { clientX: number; clientY: number } | "cursor" | "center";
3882→    retainSeed?: boolean;
3883→    fitToContent?: boolean;
3884→  }) => {
3885→    const elements = restoreElements(opts.elements, null, {
3886→      deleteInvisibleElements: true,
3887→    });
3888→    const [minX, minY, maxX, maxY] = getCommonBounds(elements);
3889→
3890→    const elementsCenterX = distance(minX, maxX) / 2;
3891→    const elementsCenterY = distance(minY, maxY) / 2;
3892→
3893→    const clientX =
3894→      typeof opts.position === "object"
3895→        ? opts.position.clientX
3896→        : opts.position === "cursor"
3897→        ? this.lastViewportPosition.x
3898→        : this.state.width / 2 + this.state.offsetLeft;
3899→    const clientY =
3900→      typeof opts.position === "object"
3901→        ? opts.position.clientY
3902→        : opts.position === "cursor"
3903→        ? this.lastViewportPosition.y
3904→        : this.state.height / 2 + this.state.offsetTop;
3905→
3906→    const { x, y } = viewportCoordsToSceneCoords(
3907→      { clientX, clientY },
3908→      this.state,
3909→    );
3910→
3911→    const dx = x - elementsCenterX;
3912→    const dy = y - elementsCenterY;
3913→
3914→    const [gridX, gridY] = getGridPoint(dx, dy, this.getEffectiveGridSize());
3915→
3916→    const { duplicatedElements } = duplicateElements({
3917→      type: "everything",
3918→      elements: elements.map((element) => {
3919→        return newElementWith(element, {
3920→          x: element.x + gridX - minX,
3921→          y: element.y + gridY - minY,
3922→        });
3923→      }),
3924→      randomizeSeed: !opts.retainSeed,
3925→    });
3926→
3927→    const prevElements = this.scene.getElementsIncludingDeleted();
3928→    let nextElements = [...prevElements, ...duplicatedElements];
3929→
3930→    const mappedNewSceneElements = this.props.onDuplicate?.(
3931→      nextElements,
3932→      prevElements,
3933→    );
3934→
3935→    nextElements = mappedNewSceneElements || nextElements;
3936→
3937→    syncMovedIndices(nextElements, arrayToMap(duplicatedElements));
3938→
3939→    const topLayerFrame = this.getTopLayerFrameAtSceneCoords({ x, y });
3940→
3941→    if (topLayerFrame) {
3942→      const eligibleElements = filterElementsEligibleAsFrameChildren(
3943→        duplicatedElements,
3944→        topLayerFrame,
3945→      );
3946→      addElementsToFrame(
3947→        nextElements,
3948→        eligibleElements,
3949→        topLayerFrame,
3950→        this.state,
3951→      );
3952→    }
3953→
3954→    this.scene.replaceAllElements(nextElements);
3955→
3956→    duplicatedElements.forEach((newElement) => {
3957→      if (isTextElement(newElement) && isBoundToContainer(newElement)) {
3958→        const container = getContainerElement(
3959→          newElement,
3960→          this.scene.getElementsMapIncludingDeleted(),
3961→        );
3962→        redrawTextBoundingBox(newElement, container, this.scene);
3963→      }
3964→    });
3965→
3966→    // paste event may not fire FontFace loadingdone event in Safari, hence loading font faces manually
3967→    if (isSafari) {
3968→      Fonts.loadElementsFonts(duplicatedElements).then((fontFaces) => {
3969→        this.fonts.onLoaded(fontFaces);
3970→      });
3971→    }
3972→
3973→    if (opts.files) {
3974→      this.addMissingFiles(opts.files);
3975→    }
3976→
3977→    const nextElementsToSelect =
3978→      excludeElementsInFramesFromSelection(duplicatedElements);
3979→
3980→    this.store.scheduleCapture();
3981→    this.setState(
3982→      {
3983→        ...this.state,
3984→        // keep sidebar (presumably the library) open if it's docked and
3985→        // can fit.
3986→        //
3987→        // Note, we should close the sidebar only if we're dropping items
3988→        // from library, not when pasting from clipboard. Alas.
3989→        openSidebar:
3990→          this.state.openSidebar &&
3991→          this.editorInterface.canFitSidebar &&
3992→          editorJotaiStore.get(isSidebarDockedAtom)
3993→            ? this.state.openSidebar
3994→            : null,
3995→        ...selectGroupsForSelectedElements(
3996→          {
3997→            editingGroupId: null,
3998→            selectedElementIds: nextElementsToSelect.reduce(
3999→              (acc: Record<ExcalidrawElement["id"], true>, element) => {
4000→                if (!isBoundToContainer(element)) {
4001→                  acc[element.id] = true;
4002→                }
4003→                return acc;
4004→              },
4005→              {},
4006→            ),
4007→          },
4008→          this.scene.getNonDeletedElements(),
4009→          this.state,
4010→          this,
4011→        ),
4012→      },
4013→      () => {
4014→        if (opts.files) {
