        onAiRepairClick={onAiRepairClick}
        onDeleteMessage={onDeleteMessage}
        onInsertMessage={onInsertMessage}
        onRetry={onRetry}
        rateLimits={rateLimits}
        renderWelcomeScreen={renderWelcomeScreen}
        renderWarning={renderWarning}
      />
    </TTDDialogPanel>
  );
};
